search:nestjs+auth:nestjs rbac @roles @s.content:
- Use `nest generate module auth` and `nest generate guard auth`
- Implement roles using an enum like `enum Role { ADMIN, USER }`
- Create a custom decorator for setting metadata:
  ```typescript
  import { createParamDecorator, ExecutionContext } from '@nestjs/common';

  export const Roles = (...roles: string[]) => {
    return createParamDecorator(
      (data: unknown, ctx: ExecutionContext) => {
        const request = ctx.switchToHttp().getRequest();
        const user = request.user;
        if (!user || !user.roles) {
          throw new UnauthorizedException();
        }
        return user.roles.some(role => roles.includes(role));
      },
    );
  };
  ```
- Use `Reflector` to access metadata in guards:
  ```typescript
  import { Injectable, CanActivate, ExecutionContext } from '@nestjs/common';
  import { Reflector } from '@nestjs/core';

  @Injectable()
  export class RolesGuard implements CanActivate {
    constructor(private reflector: Reflector) {}

    canActivate(context: ExecutionContext): boolean {
      const requiredRoles = this.reflector.getAllAndOverride<string[]>('roles', [
        context.getHandler(),
        context.getClass(),
      ]);
      if (!requiredRoles) {
        return true;
      }
      const { user } = context.switchToHttp().getRequest();
      return requiredRoles.some(role => user.roles.includes(role));
    }
  }
  ```
- Apply roles to routes using the `@Roles` decorator:
  ```typescript
  @Controller('users')
  export class UsersController {
    @Get()
    @Roles(Role.ADMIN)
    findAll() {
      // ...
    }
  }
  ```
- Ensure your user service populates the `roles` field when fetching users.
- Update `app.module.ts` to import and use the `RolesGuard`:
  ```typescript
  import { Module } from '@nestjs/common';
  import { APP_GUARD } from '@nestjs/core';

  @Module({
    providers: [
      {
        provide: APP_GUARD,
        useClass: RolesGuard,
      },
    ],
  })
  export class AppModule {}
  ```
- Use the latest version of NestJS and related packages for compatibility and features.
